fn pass(name: &str) -> Self {
        Self {
            name: name.into(),
            status: CheckStatus::Pass,
            message: String::new(),
        }
    }
fn warn(name: &str, message: &str) -> Self {
        Self {
            name: name.into(),
            status: CheckStatus::Warn,
            message: message.into(),
        }
    }
